import React, { useState, useEffect } from 'react';
import { solveQuestion } from './services/geminiService';
import { HistoryItem, SolutionResponse, Language } from './types';
import { InputSection } from './components/InputSection';
import { AnswerSection } from './components/AnswerSection';
import { HistorySidebar } from './components/HistorySidebar';
import { Menu, GraduationCap, Github, Sparkles, AlertCircle, Globe, Feather } from 'lucide-react';

const App: React.FC = () => {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [currentQuestion, setCurrentQuestion] = useState<string>("");
  const [solution, setSolution] = useState<SolutionResponse | null>(null);
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [language, setLanguage] = useState<Language>('en');

  // Load history from local storage on mount
  useEffect(() => {
    const saved = localStorage.getItem('sqs_history');
    if (saved) {
      try {
        setHistory(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse history", e);
      }
    }
  }, []);

  // Save history to local storage whenever it changes
  useEffect(() => {
    localStorage.setItem('sqs_history', JSON.stringify(history));
  }, [history]);

  const handleSolve = async (text: string, image: File | null, audio: Blob | null) => {
    setLoading(true);
    setError(null);
    setSolution(null);
    setCurrentQuestion(text || (audio ? "Audio Question" : "Image Question"));

    try {
      const result = await solveQuestion(text, image, audio, language);
      setSolution(result);

      // Add to history
      const newHistoryItem: HistoryItem = {
        id: Date.now().toString(),
        question: text || (audio ? "Audio Question" : (image ? "Image Question" : "Unknown Question")),
        timestamp: Date.now(),
        solution: result,
      };

      setHistory((prev) => [newHistoryItem, ...prev].slice(0, 50)); // Keep last 50
    } catch (err: any) {
      console.error(err);
      let errorMessage = language === 'ur' 
        ? "سوال حل کرنے میں ناکامی۔ براہ کرم دوبارہ کوشش کریں۔" 
        : "Failed to solve the question. Please try again.";

      if (err.message && err.message.includes("API key")) {
        errorMessage = language === 'ur' 
          ? "API کنفیگریشن کی خرابی: براہ کرم API کلید چیک کریں۔"
          : "API Configuration Error: Please check the API key.";
      }
      setError(errorMessage);
    } finally {
      setLoading(false);
    }
  };

  const handleSelectHistory = (item: HistoryItem) => {
    setSolution(item.solution);
    setCurrentQuestion(item.question);
    setError(null);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const isUrdu = language === 'ur';

  return (
    <div className={`min-h-screen relative bg-slate-50 ${isUrdu ? 'font-[sans-serif]' : ''}`}>

      {/* Clean Background - Removed distracting blobs */}
      <div className="fixed top-0 left-0 w-full h-full bg-[radial-gradient(ellipse_at_top,_var(--tw-gradient-stops))] from-slate-100 via-slate-50 to-slate-50 -z-10 pointer-events-none"></div>

      {/* Navbar */}
      <header className="sticky top-0 z-30 bg-white/80 backdrop-blur-md border-b border-slate-200/60 shadow-sm transition-all duration-300">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-20 flex items-center justify-between">
          <div className="flex items-center space-x-4">
            <button 
              onClick={() => setIsSidebarOpen(!isSidebarOpen)}
              className="p-2.5 -ml-2 text-slate-600 hover:text-indigo-600 hover:bg-slate-100 rounded-xl transition-all duration-200 active:scale-95"
            >
              <Menu size={24} />
            </button>

            {/* Branding Section */}
            <div className="flex items-center space-x-3 group cursor-pointer" onClick={() => { setSolution(null); setError(null); }}>
              <div className="relative h-10 w-10 flex-shrink-0">
                <img 
                    src="/logo.png" 
                    alt="Logo" 
                    className="relative h-full w-full object-contain rounded-lg"
                    onError={(e) => {
                        e.currentTarget.style.display = 'none';
                        const fallback = document.getElementById('logo-fallback');
                        if (fallback) fallback.style.display = 'flex';
                    }}
                />
                <div id="logo-fallback" className="hidden absolute inset-0 bg-emerald-600 rounded-lg items-center justify-center text-white shadow-sm">
                     <span className="font-bold text-sm">AS</span>
                </div>
              </div>

              <div className="hidden sm:flex flex-col justify-center">
                 <h1 className="text-lg font-bold tracking-tight text-slate-800 leading-none">
                    Anwar Ali Sehar
                 </h1>
                 <span className="text-[10px] font-semibold text-slate-500 uppercase tracking-widest mt-0.5">
                    Student Question Solver
                 </span>
              </div>
            </div>
          </div>

          <div className="flex items-center space-x-3 sm:space-x-4">
            {/* Language Selector */}
            <div className="flex items-center bg-slate-100 p-1 rounded-lg border border-slate-200">
                <button 
                    onClick={() => setLanguage('en')}
                    className={`px-3 py-1 text-xs font-bold rounded-md transition-all duration-200 ${!isUrdu ? 'bg-white text-slate-900 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                >
                    ENG
                </button>
                <button 
                    onClick={() => setLanguage('ur')}
                    className={`px-3 py-1 text-xs font-bold rounded-md transition-all duration-200 ${isUrdu ? 'bg-white text-slate-900 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                >
                    اردو
                </button>
            </div>
          </div>
        </div>
      </header>

      {/* Main Layout */}
      <div className="flex">

        {/* Sidebar */}
        <HistorySidebar 
          history={history} 
          isOpen={isSidebarOpen} 
          onClose={() => setIsSidebarOpen(false)} 
          onSelect={handleSelectHistory}
          language={language}
        />

        {/* Content */}
        <main className={`flex-1 transition-all duration-300 ${isSidebarOpen ? 'md:ml-72' : ''} p-4 sm:p-6 lg:p-8 max-w-5xl mx-auto w-full`}>

          <div className="space-y-12 pb-20">
            {/* Hero Text */}
            {!solution && !loading && (
              <div className="text-center py-12 md:py-20 space-y-6 animate-fade-in-up">
                <div className="inline-flex items-center px-4 py-2 rounded-full bg-white border border-slate-200 text-slate-600 text-sm font-medium mb-4 shadow-sm cursor-default">
                  <Sparkles size={14} className="mr-2 text-emerald-500" />
                  {isUrdu ? 'AI سے چلنے والا اسٹڈی ساتھی' : 'AI-Powered Study Companion'}
                </div>
                {isUrdu ? (
                     <h2 className="text-4xl md:text-5xl font-extrabold text-slate-800 tracking-tight leading-tight" dir="rtl">
                     کسی بھی مضمون میں مہارت حاصل کریں
                   </h2>
                ) : (
                    <h2 className="text-4xl md:text-5xl font-extrabold text-slate-800 tracking-tight leading-[1.15]">
                    Master any subject in seconds.
                    </h2>
                )}
                <p className={`text-lg text-slate-500 max-w-2xl mx-auto leading-relaxed px-4 ${isUrdu ? 'font-[sans-serif]' : ''}`} dir={isUrdu ? 'rtl' : 'ltr'}>
                  {isUrdu 
                    ? 'فوری بصری وضاحت حاصل کرنے کے لیے تصویر اپ لوڈ کریں، اپنی آواز ریکارڈ کریں، یا کوئی سوال ٹائپ کریں۔' 
                    : 'Upload a photo, record your voice, or type a question to get instant visual explanations.'}
                </p>
              </div>
            )}

            {/* Error Banner */}
            {error && (
              <div className="max-w-3xl mx-auto bg-red-50 border border-red-100 text-red-700 p-4 rounded-xl flex items-center justify-center animate-fade-in-up shadow-sm">
                <AlertCircle className="mr-2 flex-shrink-0" size={20} />
                <span className="font-medium">{error}</span>
              </div>
            )}

            {/* Input Section */}
            <div className={`${solution ? '' : 'transform hover:-translate-y-1 transition-transform duration-300'}`}>
               <InputSection onSolve={handleSolve} isLoading={loading} language={language} />
            </div>

            {/* Results Section */}
            {solution && (
              <div className="animate-fade-in-up">
                 <AnswerSection solution={solution} language={language} />
              </div>
            )}

          </div>

        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useRef, useState } from 'react';
import { Camera, Mic, Image as ImageIcon, X, StopCircle, Sparkles, ArrowRight } from 'lucide-react';
import { useAudioRecorder } from '../hooks/useAudioRecorder';
import { Language } from '../types';

interface InputSectionProps {
  onSolve: (text: string, image: File | null, audio: Blob | null) => void;
  isLoading: boolean;
  language: Language;
}

export const InputSection: React.FC<InputSectionProps> = ({ onSolve, isLoading, language }) => {
  const [text, setText] = useState('');
  const [selectedImage, setSelectedImage] = useState<File | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const { isRecording, audioBlob, startRecording, stopRecording, clearAudio } = useAudioRecorder();
  const [isFocused, setIsFocused] = useState(false);

  const isUrdu = language === 'ur';
  const placeholder = isUrdu 
    ? "اپنا سوال یہاں لکھیں، یا آواز/کیمرہ استعمال کریں..." 
    : "Type your question here, or use voice/camera...";

  const solveText = isUrdu ? "حل کریں" : "Solve";
  const solvingText = isUrdu ? "...حل ہو رہا ہے" : "Solving...";
  const recordingText = isUrdu ? "رکارڈنگ ہو رہی ہے" : "Recording...";
  const imageAttachedText = isUrdu ? "تصویر منسلک ہے" : "Image Attached";
  const audioAttachedText = isUrdu ? "آواز ریکارڈ ہو گئی" : "Voice Recording Attached";

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setSelectedImage(e.target.files[0]);
    }
  };

  const removeImage = () => {
    setSelectedImage(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!text && !selectedImage && !audioBlob) return;
    onSolve(text, selectedImage, audioBlob);
  };

  const handleContainerClick = (e: React.MouseEvent) => {
    // Prevent focusing if clicking on buttons/controls
    if ((e.target as HTMLElement).tagName === 'BUTTON' || (e.target as HTMLElement).closest('button')) {
      return;
    }
    textareaRef.current?.focus();
  };

  return (
    <div className="relative w-full max-w-3xl mx-auto">
      <div 
        dir={isUrdu ? 'rtl' : 'ltr'}
        className={`
        relative bg-white rounded-2xl p-6 w-full transition-all duration-300 cursor-text
        border border-slate-200 shadow-xl shadow-slate-200/50
        ${isFocused ? 'ring-2 ring-emerald-500/20 border-emerald-500/50' : ''}
      `}>
        <form onSubmit={handleSubmit} className="space-y-4">

          {/* Text Input */}
          <div className="relative group">
            <textarea
              ref={textareaRef}
              value={text}
              onChange={(e) => setText(e.target.value)}
              onFocus={() => setIsFocused(true)}
              onBlur={() => setIsFocused(false)}
              placeholder={placeholder}
              className={`w-full p-2 text-lg bg-transparent border-0 focus:ring-0 text-slate-800 placeholder-slate-400 resize-none leading-relaxed selection:bg-emerald-100 ${isUrdu ? 'font-[sans-serif]' : ''}`}
              style={{ minHeight: '120px' }}
              disabled={isLoading}
            />
          </div>

          {/* Attachments Preview */}
          {(selectedImage || audioBlob) && (
              <div className="flex flex-wrap gap-3 animate-fade-in-up py-3 border-t border-slate-50">
                  {selectedImage && (
                      <div className="relative group inline-block">
                          <div className="flex items-center space-x-2 bg-slate-50 px-3 py-2 rounded-lg border border-slate-200">
                              <div className="p-1 bg-white rounded shadow-sm">
                                <ImageIcon size={16} className="text-slate-600"/>
                              </div>
                              <span className="text-sm text-slate-700 truncate max-w-[150px] font-medium">
                                {selectedImage.name || imageAttachedText}
                              </span>
                          </div>
                          <button 
                              type="button" 
                              onClick={(e) => { e.stopPropagation(); removeImage(); }}
                              className={`absolute -top-2 bg-white text-slate-500 border border-slate-200 rounded-full p-1 shadow-sm hover:bg-slate-50 hover:text-red-500 transition-all ${isUrdu ? '-left-2' : '-right-2'}`}
                          >
                              <X size={12} />
                          </button>
                      </div>
                  )}
                  {audioBlob && (
                      <div className="relative group inline-block">
                          <div className="flex items-center space-x-2 bg-slate-50 px-3 py-2 rounded-lg border border-slate-200">
                              <div className="p-1 bg-white rounded shadow-sm animate-pulse">
                                <Mic size={16} className="text-red-500"/>
                              </div>
                              <span className="text-sm text-slate-700 font-medium">{audioAttachedText}</span>
                          </div>
                          <button 
                              type="button" 
                              onClick={(e) => { e.stopPropagation(); clearAudio(); }}
                              className={`absolute -top-2 bg-white text-slate-500 border border-slate-200 rounded-full p-1 shadow-sm hover:bg-slate-50 hover:text-red-500 transition-all ${isUrdu ? '-left-2' : '-right-2'}`}
                          >
                              <X size={12} />
                          </button>
                      </div>
                  )}
              </div>
          )}

          {/* Controls */}
          <div className="flex items-center justify-between pt-4 border-t border-slate-100 mt-2">
            <div className="flex items-center space-x-2">

              {/* Image Upload Button */}
              <button
                type="button"
                onClick={(e) => { e.stopPropagation(); fileInputRef.current?.click(); }}
                className="p-2.5 text-slate-500 hover:text-slate-800 hover:bg-slate-100 rounded-xl transition-all duration-200"
                title={isUrdu ? "تصویر اپ لوڈ کریں" : "Upload Image"}
                disabled={isLoading}
              >
                <Camera size={22} />
                <input
                  ref={fileInputRef}
                  type="file"
                  accept="image/*"
                  className="hidden"
                  onChange={handleImageUpload}
                />
              </button>

              {/* Voice Record Button */}
              <button
                type="button"
                onClick={(e) => { e.stopPropagation(); isRecording ? stopRecording() : startRecording(); }}
                className={`p-2.5 rounded-xl transition-all duration-300 flex items-center space-x-2 ${
                  isRecording 
                    ? 'bg-red-50 text-red-600 ring-1 ring-red-100 animate-pulse' 
                    : 'text-slate-500 hover:text-slate-800 hover:bg-slate-100'
                }`}
                title={isRecording ? (isUrdu ? "ریکارڈنگ روکیں" : "Stop Recording") : (isUrdu ? "آواز ریکارڈ کریں" : "Record Voice")}
                disabled={isLoading}
              >
                <div className="relative z-10">
                    {isRecording ? <StopCircle size={22} /> : <Mic size={22} />}
                </div>
              </button>
            </div>

            {/* Submit Button */}
            <button
              type="submit"
              onClick={(e) => e.stopPropagation()}
              disabled={isLoading || (!text && !selectedImage && !audioBlob)}
              className={`
                flex items-center space-x-2 px-6 py-2.5 rounded-xl font-bold text-white transition-all duration-300
                ${isLoading || (!text && !selectedImage && !audioBlob)
                  ? 'bg-slate-100 text-slate-300 cursor-not-allowed'
                  : 'bg-slate-900 hover:bg-slate-800 hover:-translate-y-0.5 shadow-md shadow-slate-200'
                }
              `}
            >
              {isLoading ? (
                <>
                  <svg className="animate-spin -ml-1 mr-2 h-4 w-4 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  <span>{solvingText}</span>
                </>
              ) : (
                <>
                  <span className={`${isUrdu ? 'ml-2' : ''} hidden sm:inline`}>{solveText}</span>
                  {(!text && !selectedImage && !audioBlob) ? <Sparkles size={16} /> : (isUrdu ? <ArrowRight size={18} className="transform rotate-180" /> : <ArrowRight size={18} />)}
                </>
              )}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { SolutionResponse, AnswerMode, Language } from '../types';
import { MermaidDiagram } from './MermaidDiagram';
import { BookOpen, List, Image as ImageIcon, Zap, FileText, Download, PenTool, Layers, Grid, ZoomIn, ZoomOut, RotateCcw, Save, Copy, Check, Feather, Notebook, FileImage, FileDown, ChevronDown } from 'lucide-react';
import ReactMarkdown from 'react-markdown';

declare global {
  interface Window {
    html2pdf: any;
    html2canvas: any;
  }
}

interface AnswerSectionProps {
  solution: SolutionResponse;
  language: Language;
}

export const AnswerSection: React.FC<AnswerSectionProps> = ({ solution, language }) => {
  const [activeTab, setActiveTab] = useState<AnswerMode>(AnswerMode.SIMPLE);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);
  const [copiedSection, setCopiedSection] = useState<string | null>(null);
  const [activeDownloadMenu, setActiveDownloadMenu] = useState<string | null>(null); // Track which menu is open
  const isUrdu = language === 'ur';

  // Visual Section State
  const [zoomLevel, setZoomLevel] = useState(1);
  const [pan, setPan] = useState({ x: 0, y: 0 });
  const [isDragging, setIsDragging] = useState(false);

  const dragStartRef = useRef({ x: 0, y: 0 });
  const visualContainerRef = useRef<HTMLDivElement>(null);
  const menuRef = useRef<HTMLDivElement>(null);

  // Close menus when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
        setActiveDownloadMenu(null);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Translations
  const t = {
    simple: { en: 'Simple', ur: 'آسان' },
    steps: { en: 'Steps', ur: 'مراحل' },
    studyNotes: { en: 'Study Notes', ur: 'اسٹڈی نوٹس' },
    easyNotes: { en: 'Easy Notes', ur: 'آسان نوٹس' },
    visual: { en: 'Visual', ur: 'تصویر' },
    short: { en: 'Short', ur: 'مختصر' },
    detailed: { en: 'Detailed', ur: 'تفصیلی' },
    simpleTitle: { en: 'Simple Explanation', ur: 'آسان وضاحت' },
    stepsTitle: { en: 'Step-by-Step Breakdown', ur: 'مرحلہ وار تفصیل' },
    studyNotesTitle: { en: 'Student Notebook (Formal)', ur: 'طالب علم نوٹ بک' },
    easyNotesTitle: { en: 'Simplified Easy Notes', ur: 'بچوں کے لیے آسان نوٹس' },
    visualTitle: { en: 'Visual Explanation', ur: 'بصری وضاحت' },
    shortTitle: { en: 'Quick Summary', ur: 'فوری خلاصہ' },
    detailedTitle: { en: 'Detailed Analysis', ur: 'تفصیلی تجزیہ' },
    savePdf: { en: 'Download Full Answer PDF', ur: 'پورا جواب PDF ڈاؤن لوڈ کریں' },
    generating: { en: 'Generating...', ur: 'بن رہا ہے...' },
    downloadOptions: { en: 'Download', ur: 'ڈاؤن لوڈ' },
    downloadJpg: { en: 'Download JPG', ur: 'JPG ڈاؤن لوڈ' },
    downloadPdf: { en: 'Download PDF', ur: 'PDF ڈاؤن لوڈ' },
    systemDiagram: { en: 'System Diagram', ur: 'سسٹم ڈایاگرام' },
    aiGenerated: { en: 'AI Generated Visualization', ur: 'AI کی تیار کردہ تصویر' },
    diagramHelp: { en: 'Pan to explore. Diagrams are automatically generated.', ur: 'تصویر کو گھسیٹ کر دیکھیں۔ تصاویر خودکار طور پر بنتی ہیں۔' },
    copy: { en: 'Copy', ur: 'کاپی کریں' },
    copied: { en: 'Copied!', ur: 'کاپی ہو گیا!' }
  };

  const getT = (key: keyof typeof t) => t[key][language];

  const getContent = (field: keyof SolutionResponse) => {
    const data = solution[field] as any;
    if (typeof data === 'string') return data;
    return data[language] || data['en'];
  };

  // --- Actions ---

  const handleCopy = (text: string, sectionId: string) => {
    navigator.clipboard.writeText(text);
    setCopiedSection(sectionId);
    setTimeout(() => setCopiedSection(null), 2000);
  };

  // Generic Download Function
  const handleSectionDownload = async (format: 'jpg' | 'pdf', elementId: string, sectionTitle: string) => {
    setActiveDownloadMenu(null); // Close menu
    const element = document.getElementById(elementId);
    if (!element) return;

    // Use Visual's SVG logic if it's the visual section and JPG
    if (elementId === 'visual-content-area' && format === 'jpg') {
        handleDownloadVisualJPG();
        return;
    }

    const filename = `${getContent('subject').replace(/\s+/g, '_')}_${sectionTitle.replace(/\s+/g, '_')}`;

    if (format === 'pdf') {
        // PDF Export using html2pdf
        if (window.html2pdf) {
            const opt = {
                margin: [0.3, 0.3], // Small margin
                filename: `${filename}.pdf`,
                image: { type: 'jpeg', quality: 0.98 },
                html2canvas: { scale: 2, useCORS: true },
                jsPDF: { unit: 'in', format: 'letter', orientation: 'portrait' },
                pagebreak: { mode: ['avoid-all', 'css', 'legacy'] }
            };
            try {
                await window.html2pdf().set(opt).from(element).save();
            } catch (e) {
                console.error("PDF generation failed", e);
                alert("Could not generate PDF.");
            }
        }
    } else {
        // JPG Export using html2canvas
        if (window.html2canvas) {
             try {
                // Ensure the background is white (html2canvas defaults to transparent sometimes)
                const canvas = await window.html2canvas(element, { 
                    scale: 2, 
                    useCORS: true,
                    backgroundColor: '#ffffff'
                });

                const link = document.createElement('a');
                link.download = `${filename}.jpg`;
                link.href = canvas.toDataURL('image/jpeg', 0.95);
                document.body.appendChild(link);
                link.click();
                document.body.removeChild(link);
             } catch (e) {
                 console.error("JPG generation failed", e);
                 alert("Could not generate JPG.");
             }
        } else {
            alert("Image generator not loaded yet. Please try again in a moment.");
        }
    }
  };

  // Specific Visual SVG Export (Better Quality for Diagrams)
  const handleDownloadVisualJPG = () => {
    const svg = visualContainerRef.current?.querySelector('svg');
    if (svg) {
        const scale = 3;
        const svgSize = svg.getBoundingClientRect();
        const width = svgSize.width;
        const height = svgSize.height;

        const canvas = document.createElement('canvas');
        canvas.width = width * scale;
        canvas.height = height * scale;
        const ctx = canvas.getContext('2d');

        if (!ctx) return;

        const serializer = new XMLSerializer();
        let svgData = serializer.serializeToString(svg);
        if (!svgData.match(/^<svg[^>]+xmlns="http\:\/\/www\.w3\.org\/2000\/svg"/)) {
            svgData = svgData.replace(/^<svg/, '<svg xmlns="http://www.w3.org/2000/svg"');
        }

        const img = new Image();
        img.crossOrigin = "anonymous";
        img.onload = () => {
            ctx.fillStyle = "#ffffff";
            ctx.fillRect(0, 0, canvas.width, canvas.height);
            ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
            try {
                const jpgUrl = canvas.toDataURL("image/jpeg", 0.95);
                const link = document.createElement('a');
                link.href = jpgUrl;
                link.download = `${getContent('subject')}_Diagram.jpg`;
                document.body.appendChild(link);
                link.click();
                document.body.removeChild(link);
            } catch (e) { console.error(e); }
            URL.revokeObjectURL(url);
        };
        const svgBlob = new Blob([svgData], {type: 'image/svg+xml;charset=utf-8'});
        const url = URL.createObjectURL(svgBlob);
        img.src = url;
    }
  };

