    { id: AnswerMode.EASY_NOTES, label: getT('easyNotes'), icon: <Feather size={16} /> },
    { id: AnswerMode.VISUAL, label: getT('visual'), icon: <ImageIcon size={16} /> },
    { id: AnswerMode.SHORT, label: getT('short'), icon: <Zap size={16} /> },
    { id: AnswerMode.DETAILED, label: getT('detailed'), icon: <FileText size={16} /> },
  ];

  return (
    <div className="w-full mt-8" dir={isUrdu ? 'rtl' : 'ltr'}>
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-6">
        <span className="inline-flex items-center px-4 py-1.5 bg-slate-100 text-slate-700 rounded-full text-sm font-bold tracking-wide uppercase border border-slate-200">
          <span className={`w-2 h-2 bg-emerald-500 rounded-full ${isUrdu ? 'ml-2' : 'mr-2'}`}></span>
          {subjectText}
        </span>
        <button 
          onClick={handleFullDownload}
          disabled={isGeneratingPdf}
          className="group flex items-center space-x-2 text-slate-500 hover:text-indigo-600 transition-colors text-sm font-medium mt-3 sm:mt-0 no-print"
        >
          <div className="p-2 bg-white rounded-full shadow-sm group-hover:shadow-md border border-slate-100 transition-all">
            {isGeneratingPdf ? <div className="animate-spin w-4 h-4 border-2 border-indigo-500 border-t-transparent rounded-full"></div> : <Download size={16} />}
          </div>
          <span>{isGeneratingPdf ? getT('generating') : getT('savePdf')}</span>
        </button>
      </div>

      {/* Tabs Navigation */}
      <div className="flex flex-wrap gap-2 mb-8 no-print">
        {tabs.map((tab) => {
             const isActive = activeTab === tab.id;
             return (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id)}
                className={`
                  flex items-center space-x-2 px-4 py-2.5 rounded-full transition-all duration-300 font-medium text-sm flex-1 sm:flex-none justify-center
                  ${isActive 
                    ? 'bg-slate-900 text-white shadow-md' 
                    : 'bg-white text-slate-500 hover:bg-slate-50 border border-slate-200 hover:text-slate-700'
                  }
                `}
              >
                <span className={`transition-colors ${isActive ? 'text-white' : 'text-slate-400'}`}>
                    {tab.icon}
                </span>
                <span>{tab.label}</span>
              </button>
            );
        })}
      </div>

      {/* Content Area */}
      <div id="answer-content-export" className="min-h-[300px]">
        {renderContent()}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { solveQuestion } from './services/geminiService';
import { HistoryItem, SolutionResponse, Language } from './types';
import { InputSection } from './components/InputSection';
import { AnswerSection } from './components/AnswerSection';
import { HistorySidebar } from './components/HistorySidebar';
import { Menu, GraduationCap, Github, Sparkles, AlertCircle, Globe, Feather } from 'lucide-react';

const App: React.FC = () => {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [currentQuestion, setCurrentQuestion] = useState<string>("");
  const [solution, setSolution] = useState<SolutionResponse | null>(null);
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [language, setLanguage] = useState<Language>('en');

  // Load history from local storage on mount
  useEffect(() => {
    const saved = localStorage.getItem('sqs_history');
    if (saved) {
      try {
        setHistory(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse history", e);
      }
    }
  }, []);

  // Save history to local storage whenever it changes
  useEffect(() => {
    localStorage.setItem('sqs_history', JSON.stringify(history));
  }, [history]);

  const handleSolve = async (text: string, image: File | null, audio: Blob | null) => {
    setLoading(true);
    setError(null);
    setSolution(null);
    setCurrentQuestion(text || (audio ? "Audio Question" : "Image Question"));

    try {
      const result = await solveQuestion(text, image, audio, language);
      setSolution(result);

      // Add to history
      const newHistoryItem: HistoryItem = {
        id: Date.now().toString(),
        question: text || (audio ? "Audio Question" : (image ? "Image Question" : "Unknown Question")),
        timestamp: Date.now(),
        solution: result,
      };

      setHistory((prev) => [newHistoryItem, ...prev].slice(0, 50)); // Keep last 50
    } catch (err: any) {
      console.error(err);
      let errorMessage = language === 'ur' 
        ? "سوال حل کرنے میں ناکامی۔ براہ کرم دوبارہ کوشش کریں۔" 
        : "Failed to solve the question. Please try again.";

      if (err.message && err.message.includes("API key")) {
        errorMessage = language === 'ur' 
          ? "API کنفیگریشن کی خرابی: براہ کرم API کلید چیک کریں۔"
          : "API Configuration Error: Please check the API key.";
      }
      setError(errorMessage);
    } finally {
      setLoading(false);
    }
  };

  const handleSelectHistory = (item: HistoryItem) => {
    setSolution(item.solution);
    setCurrentQuestion(item.question);
    setError(null);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const isUrdu = language === 'ur';

  return (
    <div className={`min-h-screen relative bg-slate-50 overflow-hidden ${isUrdu ? 'font-[sans-serif]' : ''}`}>

      {/* Background Blobs */}
      <div className="fixed top-0 left-0 w-full h-full overflow-hidden -z-10 pointer-events-none">
        <div className="absolute top-0 left-1/4 w-96 h-96 bg-purple-300 rounded-full mix-blend-multiply filter blur-3xl opacity-30 animate-blob"></div>
        <div className="absolute top-0 right-1/4 w-96 h-96 bg-yellow-300 rounded-full mix-blend-multiply filter blur-3xl opacity-30 animate-blob animation-delay-2000"></div>
        <div className="absolute -bottom-32 left-1/3 w-96 h-96 bg-pink-300 rounded-full mix-blend-multiply filter blur-3xl opacity-30 animate-blob animation-delay-4000"></div>
      </div>

      {/* Navbar */}
      <header className="sticky top-0 z-30 bg-white/80 backdrop-blur-md border-b border-slate-200/60 shadow-sm transition-all duration-300">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-20 flex items-center justify-between">
          <div className="flex items-center space-x-4">
            <button 
              onClick={() => setIsSidebarOpen(!isSidebarOpen)}
              className="p-2.5 -ml-2 text-slate-600 hover:text-indigo-600 hover:bg-slate-100 rounded-xl transition-all duration-200 active:scale-95"
            >
              <Menu size={24} />
            </button>

            {/* Branding Section */}
            <div className="flex items-center space-x-3 group cursor-pointer" onClick={() => { setSolution(null); setError(null); }}>
              <div className="relative h-10 w-10 flex-shrink-0">
                <img 
                    src="/logo.png" 
                    alt="Logo" 
                    className="relative h-full w-full object-contain rounded-lg shadow-sm"
                    onError={(e) => {
                        e.currentTarget.style.display = 'none';
                        const fallback = document.getElementById('logo-fallback');
                        if (fallback) fallback.style.display = 'flex';
                    }}
                />
                <div id="logo-fallback" className="hidden absolute inset-0 bg-gradient-to-br from-emerald-500 to-teal-600 rounded-lg items-center justify-center text-white shadow-sm">
                     <span className="font-bold text-sm">AS</span>
                </div>
              </div>

              <div className="hidden sm:flex flex-col justify-center">
                 <h1 className="text-lg font-bold tracking-tight text-slate-800 leading-none">
                    Anwar Ali Sehar
                 </h1>
                 <span className="text-[10px] font-semibold text-slate-500 uppercase tracking-widest mt-0.5 group-hover:text-indigo-600 transition-colors">
                    Student Question Solver
                 </span>
              </div>
            </div>
          </div>

          <div className="flex items-center space-x-3 sm:space-x-4">
            {/* Language Selector */}
            <div className="flex items-center bg-slate-100 p-1 rounded-lg border border-slate-200">
                <button 
                    onClick={() => setLanguage('en')}
                    className={`px-3 py-1 text-xs font-bold rounded-md transition-all duration-200 ${!isUrdu ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                >
                    ENG
                </button>
                <button 
                    onClick={() => setLanguage('ur')}
                    className={`px-3 py-1 text-xs font-bold rounded-md transition-all duration-200 ${isUrdu ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                >
                    اردو
                </button>
            </div>
          </div>
        </div>
      </header>

      {/* Main Layout */}
      <div className="flex">

        {/* Sidebar */}
        <HistorySidebar 
          history={history} 
          isOpen={isSidebarOpen} 
          onClose={() => setIsSidebarOpen(false)} 
          onSelect={handleSelectHistory}
          language={language}
        />

        {/* Content */}
        <main className={`flex-1 transition-all duration-300 ${isSidebarOpen ? 'md:ml-72' : ''} p-4 sm:p-6 lg:p-8 max-w-5xl mx-auto w-full`}>

          <div className="space-y-12 pb-20">
            {/* Hero Text */}
            {!solution && !loading && (
              <div className="text-center py-12 md:py-20 space-y-6 animate-fade-in-up">
                <div className="inline-flex items-center px-4 py-2 rounded-full bg-white/80 backdrop-blur-sm border border-slate-200 text-slate-600 text-sm font-medium mb-4 shadow-sm cursor-default hover:shadow-md transition-shadow">
                  <Sparkles size={14} className="mr-2 text-emerald-500" />
                  {isUrdu ? 'AI سے چلنے والا اسٹڈی ساتھی' : 'AI-Powered Study Companion'}
                </div>
                {isUrdu ? (
                     <h2 className="text-4xl md:text-5xl font-extrabold text-transparent bg-clip-text bg-gradient-to-r from-slate-900 via-indigo-800 to-slate-900 tracking-tight leading-tight" dir="rtl">
                     کسی بھی مضمون میں مہارت حاصل کریں
                   </h2>
                ) : (
                    <h2 className="text-4xl md:text-6xl font-extrabold text-transparent bg-clip-text bg-gradient-to-r from-slate-900 via-indigo-800 to-slate-900 tracking-tight leading-[1.15]">
                    Master any subject <br/> <span className="text-indigo-600">in seconds.</span>
                    </h2>
                )}
                <p className={`text-lg text-slate-500 max-w-2xl mx-auto leading-relaxed px-4 ${isUrdu ? 'font-[sans-serif]' : ''}`} dir={isUrdu ? 'rtl' : 'ltr'}>
                  {isUrdu 
                    ? 'فوری بصری وضاحت حاصل کرنے کے لیے تصویر اپ لوڈ کریں، اپنی آواز ریکارڈ کریں، یا کوئی سوال ٹائپ کریں۔' 
                    : 'Upload a photo, record your voice, or type a question to get instant visual explanations.'}
                </p>
              </div>
            )}

            {/* Error Banner */}
            {error && (
              <div className="max-w-3xl mx-auto bg-red-50 border border-red-100 text-red-700 p-4 rounded-xl flex items-center justify-center animate-fade-in-up shadow-sm">
                <AlertCircle className="mr-2 flex-shrink-0" size={20} />
                <span className="font-medium">{error}</span>
              </div>
            )}

            {/* Input Section */}
            <div className={`${solution ? '' : 'transform hover:-translate-y-1 transition-transform duration-300'}`}>
               <InputSection onSolve={handleSolve} isLoading={loading} language={language} />
