                    </div>
                </div>

                <div className="bg-white px-4 py-2 border-t border-slate-100 flex justify-between items-center text-xs text-slate-400 z-10 relative">
                    <div className="flex items-center">
                         <Grid size={12} className="mr-1.5" />
                         <span>Mermaid.js Renderer v10.9</span>
                    </div>
                    <span>{getT('aiGenerated')}</span>
                </div>
            </div>
             <p className="text-center text-slate-400 text-sm mt-6 no-print">
                {getT('diagramHelp')}
            </p>
          </div>
        );
      case AnswerMode.SHORT:
        const shortText = getContent('short');
        return (
          <div className="animate-fade-in-up">
            <SectionHeader 
                title={getT('shortTitle')} 
                icon={<Zap size={18} />} 
                color="bg-orange-100 text-orange-600" 
                id="short"
                textToCopy={shortText}
            />
            <div id="short-content" className="p-8 bg-gradient-to-r from-orange-50 to-amber-50 border-l-8 border-orange-400 rounded-xl shadow-sm border-t border-r border-b border-orange-100">
               <p className="text-2xl font-medium text-slate-800 italic font-serif leading-normal">
                "{shortText}"
              </p>
            </div>
          </div>
        );
      case AnswerMode.DETAILED:
        const detailedText = getContent('detailed');
        return (
          <div className="animate-fade-in-up">
             <SectionHeader 
                title={getT('detailedTitle')} 
                icon={<FileText size={18} />} 
                color="bg-indigo-100 text-indigo-600" 
                id="detailed"
                textToCopy={detailedText}
            />
             <div id="detailed-content" className="bg-gradient-to-br from-slate-50 to-indigo-50/20 p-8 md:p-12 rounded-3xl border border-slate-200 shadow-sm">
                <div className="prose prose-lg prose-slate max-w-none">
                    <ReactMarkdown components={detailedComponents}>
                        {detailedText}
                    </ReactMarkdown>
                </div>
                <div className="mt-16 pt-8 border-t border-slate-100 flex items-center justify-center">
                    <div className="h-1.5 w-16 bg-slate-200 rounded-full"></div>
                </div>
            </div>
          </div>
        );
      default:
        return null;
    }
  };

  const subjectText = getContent('subject');

  const tabs = [
    { id: AnswerMode.SIMPLE, label: getT('simple'), icon: <BookOpen size={16} /> },
    { id: AnswerMode.STEP_BY_STEP, label: getT('steps'), icon: <List size={16} /> },
    { id: AnswerMode.HANDWRITTEN, label: getT('studyNotes'), icon: <Notebook size={16} /> },
    { id: AnswerMode.EASY_NOTES, label: getT('easyNotes'), icon: <Feather size={16} /> },
    { id: AnswerMode.VISUAL, label: getT('visual'), icon: <ImageIcon size={16} /> },
    { id: AnswerMode.SHORT, label: getT('short'), icon: <Zap size={16} /> },
    { id: AnswerMode.DETAILED, label: getT('detailed'), icon: <FileText size={16} /> },
  ];

  return (
    <div className="w-full mt-8" dir={isUrdu ? 'rtl' : 'ltr'}>
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-6">
        <span className="inline-flex items-center px-4 py-1.5 bg-white border border-slate-200 text-slate-700 rounded-full text-sm font-bold tracking-wide uppercase shadow-sm">
          <span className={`w-2 h-2 bg-emerald-500 rounded-full ${isUrdu ? 'ml-2' : 'mr-2'}`}></span>
          {subjectText}
        </span>
        <button 
          onClick={handleFullDownload}
          disabled={isGeneratingPdf}
          className="group flex items-center space-x-2 text-slate-500 hover:text-indigo-600 transition-colors text-sm font-medium mt-3 sm:mt-0 no-print"
        >
          <div className="p-2 bg-white rounded-full shadow-sm group-hover:shadow-md border border-slate-100 transition-all">
            {isGeneratingPdf ? <div className="animate-spin w-4 h-4 border-2 border-indigo-500 border-t-transparent rounded-full"></div> : <Download size={16} />}
          </div>
          <span>{isGeneratingPdf ? getT('generating') : getT('savePdf')}</span>
        </button>
      </div>

      <div className="bg-slate-100/50 p-1.5 rounded-2xl mb-8 no-print flex flex-wrap gap-1">
        {tabs.map((tab) => {
             const isActive = activeTab === tab.id;
             return (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id)}
                className={`
                  flex items-center space-x-2 px-4 py-2.5 rounded-xl transition-all duration-300 font-medium text-sm flex-1 sm:flex-none justify-center
                  ${isActive 
                    ? 'bg-white text-indigo-600 shadow-md scale-[1.02]' 
                    : 'text-slate-500 hover:bg-white/50 hover:text-slate-700'
                  }
                `}
              >
                <span className={`transition-colors ${isActive ? 'text-indigo-500' : 'text-slate-400'}`}>
                    {tab.icon}
                </span>
                <span>{tab.label}</span>
              </button>
            );
        })}
      </div>

      <div id="answer-content-export" className="min-h-[300px]">
        {renderContent()}
      </div>
    </div>
  );
};

export type Language = 'en' | 'ur';

export enum AnswerMode {
  SIMPLE = 'simple',
  STEP_BY_STEP = 'stepByStep',
  VISUAL = 'visual',
  SHORT = 'short',
  DETAILED = 'detailed',
  HANDWRITTEN = 'handwritten',
  EASY_NOTES = 'easyNotes',
}

export interface BilingualText {
  en: string;
  ur: string;
}

export interface SolutionResponse {
  simple: BilingualText;
  stepByStep: BilingualText;
  visual: BilingualText; // Mermaid diagram code
  short: BilingualText;
  detailed: BilingualText;
  handwrittenNotes: BilingualText;
  easyNotes: BilingualText; 
  subject: BilingualText;
}

export interface HistoryItem {
  id: string;
  question: string;
  timestamp: number;
  solution: SolutionResponse;
}

export interface QuestionInput {
  text: string;
  image?: File | null;
  audio?: Blob | null;
}

// Auth Types
export type UserStatus = 'pending' | 'approved' | 'rejected';
export type UserRole = 'admin' | 'user';

export interface User {
  email: string;
  password?: string;
  name: string;
  role: UserRole;
  status: UserStatus;
  createdAt: number;
}

export interface AuthState {
  user: User | null;
  isAuthenticated: boolean;
}

import React, { useState, useEffect } from 'react';
import { solveQuestion } from './services/geminiService';
import { HistoryItem, SolutionResponse, Language, User, AuthState, UserStatus } from './types';
import { InputSection } from './components/InputSection';
import { AnswerSection } from './components/AnswerSection';
import { HistorySidebar } from './components/HistorySidebar';
import { AuthForms } from './components/AuthForms';
import { AdminPanel } from './components/AdminPanel';
import { Menu, GraduationCap, Github, Sparkles, AlertCircle, Globe, Feather, LogOut, Settings, User as UserIcon } from 'lucide-react';

const ADMIN_EMAIL = "arshad2097@gmail.com";
const ADMIN_PASS = "anwar786";

const App: React.FC = () => {
  // Auth State
  const [authState, setAuthState] = useState<AuthState>({ user: null, isAuthenticated: false });
  const [view, setView] = useState<'app' | 'admin'>('app');

  // App State
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [currentQuestion, setCurrentQuestion] = useState<string>("");
  const [solution, setSolution] = useState<SolutionResponse | null>(null);
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [language, setLanguage] = useState<Language>('en');

  // Initialize Auth and Data
  useEffect(() => {
    // 1. Check for active session
    const session = localStorage.getItem('sqs_session');
    if (session) {
      setAuthState({ user: JSON.parse(session), isAuthenticated: true });
    }

    // 2. Load history
    const savedHistory = localStorage.getItem('sqs_history');
    if (savedHistory) {
      try { setHistory(JSON.parse(savedHistory)); } catch (e) { console.error(e); }
    }
  }, []);

  // Save history on change
  useEffect(() => {
    if (authState.isAuthenticated) {
      localStorage.setItem('sqs_history', JSON.stringify(history));
    }
  }, [history, authState.isAuthenticated]);

  const handleLogout = () => {
    localStorage.removeItem('sqs_session');
    setAuthState({ user: null, isAuthenticated: false });
    setView('app');
    setSolution(null);
  };

  const handleSolve = async (text: string, image: File | null, audio: Blob | null) => {
    setLoading(true);
    setError(null);
    setSolution(null);
    setCurrentQuestion(text || (audio ? "Audio Question" : "Image Question"));

    try {
      const result = await solveQuestion(text, image, audio, language);
      setSolution(result);

      const newHistoryItem: HistoryItem = {
        id: Date.now().toString(),
        question: text || (audio ? "Audio Question" : (image ? "Image Question" : "Unknown Question")),
        timestamp: Date.now(),
        solution: result,
      };

      setHistory((prev) => [newHistoryItem, ...prev].slice(0, 50));
    } catch (err: any) {
      console.error(err);
      setError(language === 'ur' ? "سوال حل کرنے میں ناکامی۔" : "Failed to solve the question.");
    } finally {
      setLoading(false);
    }
  };

  const handleSelectHistory = (item: HistoryItem) => {
    setSolution(item.solution);
    setCurrentQuestion(item.question);
    setError(null);
    setView('app');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  if (!authState.isAuthenticated) {
    return <AuthForms onLoginSuccess={(user) => setAuthState({ user, isAuthenticated: true })} adminCreds={{ email: ADMIN_EMAIL, pass: ADMIN_PASS }} />;
  }

  const isAdmin = authState.user?.email === ADMIN_EMAIL;
  const isUrdu = language === 'ur';

  return (
    <div className={`min-h-screen relative bg-slate-50 overflow-hidden ${isUrdu ? 'font-[sans-serif]' : ''}`}>
      {/* Background Blobs */}
      <div className="fixed top-0 left-0 w-full h-full overflow-hidden -z-10 pointer-events-none">
        <div className="absolute top-0 left-1/4 w-96 h-96 bg-purple-300 rounded-full mix-blend-multiply filter blur-3xl opacity-30 animate-blob"></div>
        <div className="absolute top-0 right-1/4 w-96 h-96 bg-yellow-300 rounded-full mix-blend-multiply filter blur-3xl opacity-30 animate-blob animation-delay-2000"></div>
        <div className="absolute -bottom-32 left-1/3 w-96 h-96 bg-pink-300 rounded-full mix-blend-multiply filter blur-3xl opacity-30 animate-blob animation-delay-4000"></div>
      </div>

      {/* Navbar */}
      <header className="sticky top-0 z-30 bg-white/80 backdrop-blur-md border-b border-slate-200/60 shadow-sm transition-all duration-300">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-20 flex items-center justify-between">
          <div className="flex items-center space-x-4">
            <button 
              onClick={() => setIsSidebarOpen(!isSidebarOpen)}
              className="p-2.5 -ml-2 text-slate-600 hover:text-indigo-600 hover:bg-slate-100 rounded-xl transition-all duration-200 active:scale-95"
            >
              <Menu size={24} />
            </button>

            <div className="flex items-center space-x-3 group cursor-pointer" onClick={() => { setSolution(null); setError(null); setView('app'); }}>
              <div className="relative h-10 w-10">
                <div className="absolute inset-0 bg-gradient-to-br from-emerald-500 to-teal-600 rounded-lg flex items-center justify-center text-white shadow-sm font-bold">AS</div>
              </div>
              <div className="hidden sm:flex flex-col">
                 <h1 className="text-lg font-bold text-slate-800 leading-none">Anwar Ali Sehar</h1>
                 <span className="text-[10px] font-semibold text-slate-500 uppercase tracking-widest mt-0.5">Question Solver</span>
              </div>
            </div>
          </div>

          <div className="flex items-center space-x-3 sm:space-x-4">
            {isAdmin && (
               <button 
                onClick={() => setView(view === 'admin' ? 'app' : 'admin')}
                className={`flex items-center space-x-2 px-3 py-2 rounded-xl text-sm font-bold transition-all ${view === 'admin' ? 'bg-indigo-600 text-white' : 'text-slate-600 hover:bg-slate-100'}`}
               >
                 <Settings size={18} />
                 <span className="hidden md:inline">Admin Settings</span>
               </button>
            )}

            <div className="flex items-center bg-slate-100 p-1 rounded-lg border border-slate-200">
                <button onClick={() => setLanguage('en')} className={`px-3 py-1 text-xs font-bold rounded-md transition-all ${!isUrdu ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-50'}`}>ENG</button>
                <button onClick={() => setLanguage('ur')} className={`px-3 py-1 text-xs font-bold rounded-md transition-all ${isUrdu ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-50'}`}>اردو</button>
            </div>

            <button onClick={handleLogout} className="p-2 text-slate-400 hover:text-red-500 transition-colors" title="Logout">
              <LogOut size={22} />
            </button>
          </div>
        </div>
      </header>

      <div className="flex">
        <HistorySidebar 
          history={history} 
          isOpen={isSidebarOpen} 
          onClose={() => setIsSidebarOpen(false)} 
          onSelect={handleSelectHistory}
          language={language}
        />

        <main className={`flex-1 transition-all duration-300 ${isSidebarOpen ? 'md:ml-72' : ''} p-4 sm:p-6 lg:p-8 max-w-5xl mx-auto w-full`}>
          {view === 'admin' && isAdmin ? (
            <AdminPanel />
          ) : (
            <div className="space-y-12 pb-20">
              {!solution && !loading && (
                <div className="text-center py-12 animate-fade-in-up">
                  <div className="inline-flex items-center px-4 py-2 rounded-full bg-white/80 border border-slate-200 text-slate-600 text-sm font-medium mb-4 shadow-sm">
                    <Sparkles size={14} className="mr-2 text-emerald-500" />
                    Welcome, {authState.user?.name}
                  </div>
                  <h2 className="text-4xl md:text-6xl font-extrabold text-slate-900 tracking-tight">
                    {isUrdu ? 'کسی بھی مضمون میں مہارت حاصل کریں' : 'Master any subject in seconds.'}
                  </h2>
                </div>
              )}

              {error && (
                <div className="max-w-3xl mx-auto bg-red-50 border border-red-100 text-red-700 p-4 rounded-xl flex items-center justify-center animate-fade-in-up shadow-sm">
                  <AlertCircle className="mr-2" size={20} />
                  <span className="font-medium">{error}</span>
                </div>
              )}

              <InputSection onSolve={handleSolve} isLoading={loading} language={language} />

              {solution && (
                <div className="animate-fade-in-up">
                   <AnswerSection solution={solution} language={language} />
                </div>
              )}
            </div>
          )}
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { User, UserStatus } from '../types';
import { Mail, Lock, User as UserIcon, ArrowRight, ShieldCheck, Info } from 'lucide-react';

interface AuthFormsProps {
  onLoginSuccess: (user: User) => void;
  adminCreds: { email: string; pass: string };
}

export const AuthForms: React.FC<AuthFormsProps> = ({ onLoginSuccess, adminCreds }) => {
  const [mode, setMode] = useState<'login' | 'signup'>('login');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [info, setInfo] = useState<string | null>(null);

  const getUsers = (): User[] => {
    const users = localStorage.getItem('sqs_users');
    return users ? JSON.parse(users) : [];
  };

  const getSignupConfig = () => {
    const config = localStorage.getItem('sqs_config');
    return config ? JSON.parse(config) : { allowSignup: true };
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setInfo(null);

    // Check Hardcoded Admin
    if (email === adminCreds.email && password === adminCreds.pass) {
      const adminUser: User = {
        email: adminCreds.email,
        name: "Admin",
        role: "admin",
        status: "approved",
        createdAt: Date.now()
      };
      localStorage.setItem('sqs_session', JSON.stringify(adminUser));
      onLoginSuccess(adminUser);
      return;
    }

    // Check Registered Users
    const users = getUsers();
    const user = users.find(u => u.email === email && u.password === password);

    if (!user) {
      setError("Invalid email or password.");
    } else if (user.status === 'pending') {
      setInfo("Your account is pending approval by the Admin.");
    } else if (user.status === 'rejected') {
      setError("Your account request has been rejected.");
    } else {
      localStorage.setItem('sqs_session', JSON.stringify(user));
      onLoginSuccess(user);
    }
  };

  const handleSignup = (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setInfo(null);

    if (!getSignupConfig().allowSignup) {
      setError("Registration is currently disabled by the Admin.");
      return;
    }

    const users = getUsers();
    if (users.some(u => u.email === email)) {
      setError("An account with this email already exists.");
      return;
    }

    const newUser: User = {
      email,
      password,
      name,
      role: 'user',
      status: 'pending',
      createdAt: Date.now()
    };

    localStorage.setItem('sqs_users', JSON.stringify([...users, newUser]));
    setInfo("Account created! Waiting for Admin approval.");
    setMode('login');
    setEmail('');
    setPassword('');
    setName('');
  };

  return (
    <div className="min-h-screen flex items-center justify-center p-6 bg-slate-50 relative overflow-hidden">
      {/* Background decoration */}
      <div className="absolute top-0 left-0 w-full h-full -z-10 pointer-events-none opacity-20">
        <div className="absolute top-1/4 left-1/4 w-96 h-96 bg-indigo-400 rounded-full blur-3xl animate-blob"></div>
        <div className="absolute bottom-1/4 right-1/4 w-96 h-96 bg-emerald-400 rounded-full blur-3xl animate-blob animation-delay-2000"></div>
      </div>

      <div className="w-full max-w-md animate-fade-in-up">
        <div className="bg-white/80 backdrop-blur-xl border border-slate-200 rounded-3xl p-8 shadow-2xl">
          <div className="text-center mb-10">
            <div className="inline-flex items-center justify-center w-16 h-16 bg-gradient-to-br from-indigo-500 to-violet-600 text-white rounded-2xl shadow-lg mb-4">
              <ShieldCheck size={32} />
            </div>
            <h2 className="text-2xl font-bold text-slate-900">{mode === 'login' ? 'Welcome Back' : 'Join Our Community'}</h2>
            <p className="text-slate-500 mt-2">{mode === 'login' ? 'Login to continue your learning' : 'Create an account to start solving'}</p>
          </div>

          {error && (
            <div className="mb-6 p-4 bg-red-50 border border-red-100 rounded-xl flex items-center text-red-700 text-sm">
              <AlertCircle size={18} className="mr-2 flex-shrink-0" />
              <span>{error}</span>
            </div>
          )}

          {info && (
            <div className="mb-6 p-4 bg-blue-50 border border-blue-100 rounded-xl flex items-center text-blue-700 text-sm">
              <Info size={18} className="mr-2 flex-shrink-0" />
              <span>{info}</span>
            </div>
          )}

          <form onSubmit={mode === 'login' ? handleLogin : handleSignup} className="space-y-4">
            {mode === 'signup' && (
              <div className="relative group">
                <div className="absolute inset-y-0 left-0 pl-3.5 flex items-center pointer-events-none text-slate-400 group-focus-within:text-indigo-500 transition-colors">
                  <UserIcon size={18} />
                </div>
                <input 
                  required
                  type="text" 
                  value={name}
                  onChange={e => setName(e.target.value)}
                  placeholder="Full Name"
                  className="w-full pl-11 pr-4 py-3 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 outline-none transition-all"
                />
              </div>
            )}

            <div className="relative group">
              <div className="absolute inset-y-0 left-0 pl-3.5 flex items-center pointer-events-none text-slate-400 group-focus-within:text-indigo-500 transition-colors">
                <Mail size={18} />
              </div>
              <input 
                required
                type="email" 
                value={email}
                onChange={e => setEmail(e.target.value)}
                placeholder="Email address"
                className="w-full pl-11 pr-4 py-3 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 outline-none transition-all"
              />
            </div>

            <div className="relative group">
              <div className="absolute inset-y-0 left-0 pl-3.5 flex items-center pointer-events-none text-slate-400 group-focus-within:text-indigo-500 transition-colors">
                <Lock size={18} />
              </div>
              <input 
                required
                type="password" 
                value={password}
                onChange={e => setPassword(e.target.value)}
                placeholder="Password"
                className="w-full pl-11 pr-4 py-3 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 outline-none transition-all"
              />
            </div>

            <button 
              type="submit"
              className="w-full bg-gradient-to-r from-indigo-600 to-violet-600 text-white font-bold py-3.5 rounded-xl shadow-lg shadow-indigo-200 hover:shadow-indigo-300 transform transition hover:-translate-y-0.5 active:scale-95 flex items-center justify-center space-x-2"
            >
              <span>{mode === 'login' ? 'Login Now' : 'Create Account'}</span>
              <ArrowRight size={18} />
            </button>
          </form>

          <div className="mt-8 text-center text-sm text-slate-500">
            {mode === 'login' ? (
              <p>Don't have an account? <button onClick={() => setMode('signup')} className="text-indigo-600 font-bold hover:underline">Request Signup</button></p>
            ) : (
              <p>Already have an account? <button onClick={() => setMode('login')} className="text-indigo-600 font-bold hover:underline">Login</button></p>
            )}
          </div>
        </div>

        <div className="mt-8 text-center opacity-50 text-xs text-slate-400 font-medium tracking-widest uppercase">
          Anwar Ali Sehar • Secured Learning
        </div>
      </div>
    </div>
  );
};

const AlertCircle = ({ size, className }: { size: number, className?: string }) => (
  <svg className={className} width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>
);

import React, { useState, useEffect } from 'react';
import { User, UserStatus } from '../types';
import { Check, X, Trash2, UserPlus, Shield, UserX, ToggleLeft as ToggleOff, ToggleRight as ToggleOn } from 'lucide-react';

export const AdminPanel: React.FC = () => {
  const [users, setUsers] = useState<User[]>([]);
  const [config, setConfig] = useState({ allowSignup: true });

  useEffect(() => {
    const savedUsers = localStorage.getItem('sqs_users');
    const savedConfig = localStorage.getItem('sqs_config');
    if (savedUsers) setUsers(JSON.parse(savedUsers));
    if (savedConfig) setConfig(JSON.parse(savedConfig));
  }, []);

  const saveUsers = (updatedUsers: User[]) => {
    setUsers(updatedUsers);
    localStorage.setItem('sqs_users', JSON.stringify(updatedUsers));
  };

  const toggleSignup = () => {
    const newConfig = { ...config, allowSignup: !config.allowSignup };
    setConfig(newConfig);
    localStorage.setItem('sqs_config', JSON.stringify(newConfig));
  };

  const updateUserStatus = (email: string, status: UserStatus) => {
    const updated = users.map(u => u.email === email ? { ...u, status } : u);
    saveUsers(updated);
  };

  const deleteUser = (email: string) => {
    if (window.confirm("Are you sure you want to delete this user?")) {
      saveUsers(users.filter(u => u.email !== email));
    }
  };

  const getStatusColor = (status: UserStatus) => {
    switch (status) {
      case 'approved': return 'bg-emerald-100 text-emerald-700 border-emerald-200';
      case 'rejected': return 'bg-red-100 text-red-700 border-red-200';
      default: return 'bg-amber-100 text-amber-700 border-amber-200';
    }
  };

  return (
    <div className="animate-fade-in-up space-y-8 max-w-5xl mx-auto">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Admin Dashboard</h2>
          <p className="text-slate-500">Manage user approvals and platform settings.</p>
        </div>

        <div className="flex items-center space-x-4 bg-slate-50 px-5 py-3 rounded-2xl border border-slate-100">
          <span className="text-sm font-bold text-slate-700">Public Signup</span>
          <button onClick={toggleSignup} className="text-indigo-600 transition-transform active:scale-95">
            {config.allowSignup ? <ToggleOn size={48} /> : <ToggleOff size={48} className="text-slate-400" />}
          </button>
        </div>
      </div>

      <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50 border-b border-slate-200">
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">User</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Joined</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Status</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {users.length === 0 ? (
                <tr>
                  <td colSpan={4} className="px-6 py-12 text-center text-slate-400 italic">No registered users found.</td>
                </tr>
              ) : (
                users.map((user) => (
                  <tr key={user.email} className="hover:bg-slate-50/50 transition-colors">
                    <td className="px-6 py-4">
                      <div className="flex items-center">
                        <div className="w-10 h-10 rounded-full bg-indigo-100 text-indigo-600 flex items-center justify-center font-bold mr-3">
                          {user.name.charAt(0)}
                        </div>
                        <div>
                          <div className="font-bold text-slate-800">{user.name}</div>
                          <div className="text-xs text-slate-500">{user.email}</div>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4 text-sm text-slate-500">
                      {new Date(user.createdAt).toLocaleDateString()}
                    </td>
                    <td className="px-6 py-4">
                      <span className={`px-2.5 py-1 rounded-full text-[10px] font-bold uppercase border ${getStatusColor(user.status)}`}>
                        {user.status}
                      </span>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex items-center space-x-2">
                        {user.status !== 'approved' && (
                          <button 
                            onClick={() => updateUserStatus(user.email, 'approved')}
                            className="p-2 bg-emerald-50 text-emerald-600 rounded-lg hover:bg-emerald-100 transition-colors"
                            title="Approve"
                          >
                            <Check size={18} />
                          </button>
                        )}
                        {user.status !== 'rejected' && (
                          <button 
                            onClick={() => updateUserStatus(user.email, 'rejected')}
                            className="p-2 bg-amber-50 text-amber-600 rounded-lg hover:bg-amber-100 transition-colors"
                            title="Reject"
                          >
                            <UserX size={18} />
                          </button>
                        )}
                        <button 
                          onClick={() => deleteUser(user.email)}
                          className="p-2 bg-red-50 text-red-600 rounded-lg hover:bg-red-100 transition-colors"
                          title="Delete"
                        >
                          <Trash2 size={18} />
                        </button>
                      </div>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};
